final class LocationManager: NSObject, CLLocationManagerDelegate {
    private let manager = CLLocationManager()
    var onUpdate: ((CLLocationCoordinate2D?) -> Void)?

    override init() {
        super.init()
        manager.delegate = self
        manager.desiredAccuracy = kCLLocationAccuracyHundredMeters
    }

    func request() {
        if CLLocationManager.locationServicesEnabled() {
            switch manager.authorizationStatus {
            case .notDetermined:
                manager.requestWhenInUseAuthorization()
            case .restricted, .denied:
                onUpdate?(nil)
            case .authorizedAlways, .authorizedWhenInUse:
                manager.requestLocation()
            @unknown default:
                onUpdate?(nil)
            }
        } else {
            onUpdate?(nil)
        }
    }

    func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
        switch manager.authorizationStatus {
        case .authorizedAlways, .authorizedWhenInUse:
            manager.requestLocation()
        case .restricted, .denied:
            onUpdate?(nil)
        case .notDetermined:
            break
        @unknown default:
            onUpdate?(nil)
        }
    }

    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        onUpdate?(locations.last?.coordinate)
    }

    func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        onUpdate?(nil)
    }
}

struct GoogleMapView: UIViewRepresentable {
    @Binding var userCoordinate: CLLocationCoordinate2D?
    @Binding var selectedCoordinate: CLLocationCoordinate2D?
    @Binding var zoom: Float

    final class Coordinator: NSObject, GMSMapViewDelegate {
        var parent: GoogleMapView
        let locationManager = LocationManager()

        var mapView: GMSMapView?
        var userMarker: GMSMarker?
        var pinMarker: GMSMarker?

        init(_ parent: GoogleMapView) {
            self.parent = parent
            super.init()

            locationManager.onUpdate = { [weak self] coord in
                guard let self else { return }
                DispatchQueue.main.async {
                    if let c = coord {
                        self.parent.userCoordinate = c
                        self.updateUserMarker(to: c, animated: true)
                        if self.parent.selectedCoordinate == nil {
                            self.centerCamera(on: c, zoom: self.parent.zoom, animated: true)
                        }
                    } else {
                        if self.parent.userCoordinate == nil {
                            let fallback = CLLocationCoordinate2D(latitude: 37.7749, longitude: -122.4194)
                            self.parent.userCoordinate = fallback
                            self.updateUserMarker(to: fallback, animated: false)
                            self.centerCamera(on: fallback, zoom: self.parent.zoom, animated: false)
                        }
                    }
                }
            }
        }

        func centerCamera(on coord: CLLocationCoordinate2D, zoom: Float, animated: Bool) {
            guard let mapView else { return }
            let camera = GMSCameraPosition.camera(withTarget: coord, zoom: zoom)
            if animated {
                mapView.animate(to: camera)
            } else {
                mapView.camera = camera
            }
        }

        func updateUserMarker(to coord: CLLocationCoordinate2D, animated: Bool) {
            guard let mapView else { return }
            if userMarker == nil {
                let marker = GMSMarker(position: coord)
                marker.title = "You"
                marker.icon = GMSMarker.markerImage(with: .systemBlue)
                marker.map = mapView
                userMarker = marker
            } else {
                if animated {
                    CATransaction.begin()
                    CATransaction.setAnimationDuration(0.25)
                    userMarker?.position = coord
                    CATransaction.commit()
                } else {
                    userMarker?.position = coord
                }
            }
        }

        func updatePinMarker(to coord: CLLocationCoordinate2D) {
            guard let mapView else { return }
            if pinMarker == nil {
                let marker = GMSMarker(position: coord)
                marker.title = "Selected"
                marker.snippet = "\(coord.latitude), \(coord.longitude)"
                marker.appearAnimation = .pop
                marker.map = mapView
                pinMarker = marker
            } else {
                pinMarker?.position = coord
                pinMarker?.snippet = "\(coord.latitude), \(coord.longitude)"
            }
        }

        func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
            parent.selectedCoordinate = coordinate
            updatePinMarker(to: coordinate)
        }
    }

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    func makeUIView(context: Context) -> GMSMapView {
        let initial = userCoordinate ?? CLLocationCoordinate2D(latitude: 37.7749, longitude: -122.4194)
        let camera = GMSCameraPosition.camera(withTarget: initial, zoom: zoom)
        let mapView = GMSMapView(frame: .zero, camera: camera)
        mapView.settings.compassButton = true
        mapView.settings.myLocationButton = true
        mapView.isMyLocationEnabled = true
        mapView.delegate = context.coordinator

        context.coordinator.mapView = mapView
        context.coordinator.locationManager.request()

        context.coordinator.updateUserMarker(to: initial, animated: false)
        if let sel = selectedCoordinate {
            context.coordinator.updatePinMarker(to: sel)
        }
        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {
        let target = selectedCoordinate ?? userCoordinate
        if let t = target {
            let currentZoom = uiView.camera.zoom
            if abs(currentZoom - zoom) > 0.001 {
                uiView.animate(toZoom: zoom)
            }
            if selectedCoordinate != nil {
                context.coordinator.updatePinMarker(to: t)
            } else {
                context.coordinator.updateUserMarker(to: t, animated: true)
            }
        } else {
            let currentZoom = uiView.camera.zoom
            if abs(currentZoom - zoom) > 0.001 {
                uiView.animate(toZoom: zoom)
            }
        }
    }
}

