struct DemoCardEntryView: View {
    enum Result {
        case success(last4: String)
        case failure(message: String)
    }

    var onComplete: (Result) -> Void

    @State private var cardNumber = "4242 4242 4242 4242"
    @State private var exp = "12/34"
    @State private var cvc = "123"
    @State private var zip = "94103"

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text("Add test card (local validation)")
                .font(.headline)

            VStack(spacing: 10) {
                TextField("Card number", text: $cardNumber)
                    .textContentType(.creditCardNumber)
                    .keyboardType(.numberPad)
                    .textFieldStyle(.roundedBorder)

                HStack {
                    TextField("MM/YY", text: $exp)
                        .keyboardType(.numbersAndPunctuation)
                        .textFieldStyle(.roundedBorder)

                    TextField("CVC", text: $cvc)
                        .keyboardType(.numberPad)
                        .textFieldStyle(.roundedBorder)
                }

                TextField("ZIP", text: $zip)
                    .keyboardType(.numbersAndPunctuation)
                    .textFieldStyle(.roundedBorder)

                Button {
                    validateAndReturn()
                } label: {
                    Text("Validate Card")
                        .frame(maxWidth: .infinity)
                }
                .buttonStyle(.bordered)
            }

            Text("Tip: Use 4242 4242 4242 4242 with any future date and any CVC for a successful demo.")
                .font(.caption)
                .foregroundStyle(.secondary)
        }
        .padding()
        .background(.thinMaterial)
        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
    }

    private func validateAndReturn() {
        let sanitized = cardNumber.replacingOccurrences(of: " ", with: "")
        guard sanitized.count >= 12 else {
            onComplete(.failure(message: "Invalid card number length"))
            return
        }
        guard luhnCheck(sanitized) else {
            onComplete(.failure(message: "Card number failed checksum"))
            return
        }
        guard parseExp(exp) != nil else {
            onComplete(.failure(message: "Invalid expiration date"))
            return
        }
        guard cvc.trimmingCharacters(in: .whitespacesAndNewlines).count >= 3 else {
            onComplete(.failure(message: "Invalid CVC"))
            return
        }

        let last4 = String(sanitized.suffix(4))
        onComplete(.success(last4: last4))
    }

    private func parseExp(_ s: String) -> (Int, Int)? {
        let parts = s.split(separator: "/").map { String($0) }
        guard parts.count == 2 else { return nil }
        let mm = Int(parts[0]) ?? 0
        var yy = Int(parts[1]) ?? -1
        guard (1...12).contains(mm) else { return nil }
        if yy < 0 { return nil }
        if yy < 100 { yy += 2000 }
        let now = Date()
        let cal = Calendar.current
        let cy = cal.component(.year, from: now)
        let cm = cal.component(.month, from: now)
        if yy < cy { return nil }
        if yy == cy && mm < cm { return nil }
        return (mm, yy)
    }

    private func luhnCheck(_ number: String) -> Bool {
        var sum = 0
        let digits = number.compactMap { Int(String($0)) }
        guard digits.count == number.count else { return false }
        for (idx, digit) in digits.reversed().enumerated() {
            if idx % 2 == 1 {
                var d = digit * 2
                if d > 9 { d -= 9 }
                sum += d
            } else {
                sum += digit
            }
        }
        return sum % 10 == 0
    }
}